1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const FIRST_INSURANCE_SURCHARGE = 0.1;
34	const CURSE_SURCHARGE = 0.5;
35	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const FOLLOWUP_DISCOUNT = 0.15;
40	const PROCESSING_FEE = 5;
41	
42	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
43	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
44	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
45	
46	// A block applies only to a group of exactly BLOCK_SIZE alike components,
47	// priced at BLOCK_PREMIUM; any other count is priced individually.
48	const componentBasePremium = (count: number, perComponent: number): number => {
49	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
50	  return count * perComponent;
51	};
52	
53	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
54	
55	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
56	const isMainItem = (item: Item): boolean => !isComponent(item);
57	
58	const countByType = (items: Item[]): Record<string, number> => {
59	  const counts: Record<string, number> = {};
60	  for (const item of items) {
61	    counts[item.type] = (counts[item.type] ?? 0) + 1;
62	  }
63	  return counts;
64	};
65	
66	// A surcharge rate is an additive percentage applied on top of a base premium.
67	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
68	
69	// A conditional rate: the given percentage when its condition holds, else 0.
70	// Used for both item surcharges and policy-wide discounts.
71	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
72	
73	// Item-specific surcharges are additive percentages of the item's base premium.
74	// First insurance applies to every item; the others only when their condition holds.
75	const itemSurchargeRate = (item: Item): number =>
76	  sum([
77	    FIRST_INSURANCE_SURCHARGE,
78	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
79	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
80	  ]);
81	
82	const mainItemPremium = (item: Item): number =>
83	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
84	
85	const componentGroupBases = (items: Item[]): number[] =>
86	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
87	    componentBasePremium(count, BASE_PREMIUM[type]),
88	  );
89	
90	// Sum of item base premiums with block pricing but no surcharges; the basis
91	// for policy-wide modifiers (loyalty, follow-up).
92	const policyBasePremium = (items: Item[]): number =>
93	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
94	  sum(componentGroupBases(items));
95	
96	// Sum of item premiums including item-specific surcharges (curse, high
97	// enchantment, first insurance).
98	const itemsPremium = (items: Item[]): number => {
99	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
100	  const componentsPremium = sum(
101	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
102	  );
103	  return mainItemsPremium + componentsPremium;
104	};
105	
106	// Policy-wide discounts are a rate applied to the unmodified policy base.
107	// Loyalty is one such discount; the follow-up-contract discount will be another.
108	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
109	
110	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
111	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
112	
113	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
114	  const surcharged = itemsPremium(items);
115	  const policyBase = policyBasePremium(items);
116	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
117	  const discount = policyWideDiscount(discountRate, policyBase);
118	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
119	};
120	
121	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
122	  const { yearsWithMHPCO } = scenario.customer;
123	  let quoteCount = 0;
124	  const results = scenario.steps.map((step) => {
125	    const isFollowup = quoteCount > 0;
126	    quoteCount += 1;
127	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
128	  });
129	  return { results };
130	};
