export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  // The first quote in a scenario is the initial contract; every later quote is
  // a follow-up. With only quote steps today this is exactly "not the first step".
  const results = scenario.steps.map((step, index) => {
    const isFollowup = index > 0;
    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
  });
  return { results };
};
